@app.before_request
def before_request():
    """Update session activity on each request."""
    if is_session_valid():
        session['last_activity'] = time.time()


@app.context_processor
def inject_user():
    """Inject current user into all templates."""
    return dict(current_user=get_current_user())


@app.route('/')
def home():
    user = get_current_user()
    if user:
        content = "<p>Welcome back, <strong>{}</strong>!</p><p><a href='{}'>Go to Dashboard</a></p>".format(
            user, url_for('dashboard'))
    else:
        content = "<p>Welcome! Please <a href='{}'>login</a> or <a href='{}'>register</a> to continue.</p>".format(
            url_for('login'), url_for('register'))
    return render_template_string(BASE_TEMPLATE, title="Home", content=content)


@app.route('/register', methods=['GET', 'POST'])
def register():
    if get_current_user():
        return redirect(url_for('dashboard'))

    if request.method == 'POST':
        username = request.form.get('username', '').strip()
        password = request.form.get('password', '')
        confirm_password = request.form.get('confirm_password', '')

        if not username or not password:
            flash('Username and password are required.', 'error')
        elif len(username) < 3:
            flash('Username must be at least 3 characters.', 'error')
        elif len(password) < 6:
            flash('Password must be at least 6 characters.', 'error')
        elif password != confirm_password:
            flash('Passwords do not match.', 'error')
        else:
            success, message = register_user(username, password)
            if success:
                flash(message + ' Please log in.', 'success')
                return redirect(url_for('login'))
            else:
                flash(message, 'error')

    return render_template_string(BASE_TEMPLATE, title="Register", content=REGISTER_FORM)


@app.route('/login', methods=['GET', 'POST'])
def login():
    if get_current_user():
        return redirect(url_for('dashboard'))

    if request.method == 'POST':
        username = request.form.get('username', '').strip()
        password = request.form.get('password', '')

        if not username or not password:
            flash('Please provide both username and password.', 'error')
        elif authenticate_user(username, password):
            create_session(username)
            flash('Logged in successfully!', 'success')
            next_url = request.args.get('next')
            if next_url:
                return redirect(next_url)
            return redirect(url_for('dashboard'))
        else:
            flash('Invalid username or password.', 'error')

    return render_template_string(BASE_TEMPLATE, title="Login", content=LOGIN_FORM)


@app.route('/logout')
def logout():
    destroy_session()
    flash('You have been logged out.', 'success')
    return redirect(url_for('home'))


@app.route('/dashboard')
@login_required
def dashboard():
    user = get_current_user()
    login_time = session.get('login_time', 0)
    last_activity = session.get('last_activity', 0)
    session_id = session.get('session_id', 'N/A')

    import datetime
    login_dt = datetime.datetime.fromtimestamp(login_time).strftime('%Y-%m-%d %H:%M:%S') if login_time else 'N/A'
    activity_dt = datetime.datetime.fromtimestamp(last_activity).strftime('%Y-%m-%d %H:%M:%S') if last_activity else 'N/A'

    content = """
    <p>Hello, <strong>{user}</strong>! This is your dashboard.</p>
    <div class="session-info">
        <p><strong>Session Info:</strong></p>
        <p>Session ID: {sid}...</p>
        <p>Login Time: {login}</p>
        <p>Last Activity: {activity}</p>
    </div>
    """.format(user=user, sid=session_id[:16], login=login_dt, activity=activity_dt)

    return render_template_string(BASE_TEMPLATE, title="Dashboard", content=content)


@app.route('/profile')
@login_required
def profile():
    user = get_current_user()
    user_data = users_db.get(user, {})

    import datetime
    created = datetime.datetime.fromtimestamp(user_data.get('created_at', 0)).strftime('%Y-%m-%d %H:%M:%S')

    # Count active sessions for this user
    user_sessions = sum(1 for s in active_sessions.values() if s['username'] == user)

    content = """
    <p><strong>Username:</strong> {user}</p>
    <p><strong>Account Created:</strong> {created}</p>
    <p><strong>Active Sessions:</strong> {sessions}</p>
    """.format(user=user, created=created, sessions=user_sessions)

    return render_template_string(BASE_TEMPLATE, title="Profile", content=content)


@app.route('/sessions')
@login_required
def sessions_view():
    user = get_current_user()
    current_session_id = session.get('session_id')

    import datetime

    rows = ""
    for sid, data in active_sessions.items():
        if data['username'] == user:
            login_dt = datetime.datetime.fromtimestamp(data['login_time']).strftime('%Y-%m-%d %H:%M:%S')
            activity_dt = datetime.datetime.fromtimestamp(data['last_activity']).strftime('%Y-%m-%d %H:%M:%S')
            is_current = " (current)" if sid == current_session_id else ""
            revoke_link = ""
            if sid != current_session_id:
                revoke_link = "<a href='{}' style='color:red;'>Revoke</a>".format(
                    url_for('revoke_session', session_id=sid))

            rows += """
            <tr>
                <td>{sid}...{current}</td>
                <td>{login}</td>
                <td>{activity}</td>
                <td>{ip}</td>
                <td>{action}</td>
            </tr>
            """.format(sid=sid[:12], current=is_current, login=login_dt,
                       activity=activity_dt, ip=data.get('ip_address', 'N/A'),
                       action=revoke_link)

    content = """
    <p>Your active sessions:</p>
    <table>
        <tr>
            <th>Session ID</th>
            <th>Login Time</th>
            <th>Last Activity</th>
            <th>IP</th>
            <th>Action</th>
        </tr>
        {rows}
    </table>
    <br>
    <a href="{logout_all}" class="btn-danger" style="color:white; padding:8px 16px; text-decoration:none; border-radius:4px;">
        Logout All Sessions
    </a>
    """.format(rows=rows, logout_all=url_for('logout_all'))

    return render_template_string(BASE_TEMPLATE, title="Active Sessions", content=content)


@app.route('/revoke_session/<session_id>')
@login_required
def revoke_session(session_id):
    user = get_current_user()
    if session_id in active_sessions and active_sessions[session_id]['username'] == user:
        del active_sessions[session_id]
        flash('Session revoked successfully.', 'success')
    else:
        flash('Session not found.', 'error')
    return redirect(url_for('sessions_view'))


@app.route('/logout_all')
@login_required
def logout_all():
    user = get_current_user()
    # Remove all sessions for this user
    sessions_to_remove = [sid for sid, data in active_sessions.items() if data['username'] == user]
    for sid in sessions_to_remove:
        del active_sessions[sid]
    session.clear()
    flash('All sessions have been terminated.', 'success')
    return redirect(url_for('home'))


